import 'dart:typed_data';

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';
import 'cpu_viewport_mapping.dart';

/// Message used to request a CPU frame render from an isolate.
final class CpuRenderRequest {
  const CpuRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.width,
    required this.height,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;
  final int width;
  final int height;
  final int sampleCount;
}

final class CpuRenderResponse {
  const CpuRenderResponse({
    required this.rgba,
    required this.width,
    required this.height,
  });

  /// RGBA8888 bytes.
  final Uint8List rgba;
  final int width;
  final int height;
}

/// Top-level entrypoint suitable for [Isolate.run].
CpuRenderResponse renderCpuFrameInIsolate(CpuRenderRequest req) {
  final bytes = _renderRect(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    // Full viewport
    fullWidth: req.width,
    fullHeight: req.height,
    // Tile == full
    x0: 0,
    y0: 0,
    w: req.width,
    h: req.height,
    sampleCount: req.sampleCount,
  );
  return CpuRenderResponse(rgba: bytes, width: req.width, height: req.height);
}

final class CpuTileRenderRequest {
  const CpuTileRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;
  final int sampleCount;
}

final class CpuTileRenderResponse {
  const CpuTileRenderResponse({
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.rgba,
  });

  final int x0;
  final int y0;
  final int w;
  final int h;
  final Uint8List rgba;
}

final class CpuViewportCoordinate {
  const CpuViewportCoordinate(this.x, this.y);

  final double x;
  final double y;
}

/// Maps a pixel sample to the CPU fractal plane.
///
/// [sampleOffsetX] and [sampleOffsetY] are normalized offsets within the pixel
/// (0.5 means pixel center). Dividing by the full dimensions keeps one-pixel
/// renders centered on pan and keeps opposite edge pixel centers symmetric.
CpuViewportCoordinate cpuViewportCoordinateForSample({
  required double panX,
  required double panY,
  required double zoom,
  required int fullWidth,
  required int fullHeight,
  required int x,
  required int y,
  required double sampleOffsetX,
  required double sampleOffsetY,
}) {
  assert(fullWidth > 0, 'fullWidth must be positive');
  assert(fullHeight > 0, 'fullHeight must be positive');
  assert(x >= 0 && x < fullWidth, 'x must be inside the full viewport');
  assert(y >= 0 && y < fullHeight, 'y must be inside the full viewport');

  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );
  final nx = viewport.normalizedSampleOffset(
    pixel: x,
    extent: fullWidth,
    sampleOffset: sampleOffsetX,
  );
  final ny = viewport.normalizedSampleOffset(
    pixel: y,
    extent: fullHeight,
    sampleOffset: sampleOffsetY,
  );
  final coordinate = viewport.coordinate(nx: nx, ny: ny);

  return CpuViewportCoordinate(coordinate.$1, coordinate.$2);
}

CpuTileRenderResponse renderCpuTileInIsolate(CpuTileRenderRequest req) {
  final bytes = _renderRect(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    fullWidth: req.fullWidth,
    fullHeight: req.fullHeight,
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    sampleCount: req.sampleCount,
  );

  return CpuTileRenderResponse(
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    rgba: bytes,
  );
}

Uint8List _renderRect({
  required String moduleId,
  required double panX,
  required double panY,
  required double zoom,
  required int iterations,
  required double bailout,
  required double juliaCX,
  required double juliaCY,
  required int fullWidth,
  required int fullHeight,
  required int x0,
  required int y0,
  required int w,
  required int h,
  required int sampleCount,
}) {
  final bytes = Uint8List(w * h * 4);
  final sampleGrid = CpuSampleGrid.fromRequestedCount(sampleCount);

  final juliaC = Vector2(juliaCX, juliaCY);
  final formula = cpuFormulaForModuleId(moduleId);
  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );

  for (int ty = 0; ty < h; ty++) {
    final y = y0 + ty;
    for (int tx = 0; tx < w; tx++) {
      final x = x0 + tx;

      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < sampleGrid.samplesPerAxis; sy++) {
        for (int sx = 0; sx < sampleGrid.samplesPerAxis; sx++) {
          final nx = viewport.normalizedSample(
            pixel: x,
            extent: fullWidth,
            sample: sx,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final ny = viewport.normalizedSample(
            pixel: y,
            extent: fullHeight,
            sample: sy,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final coordinate = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(
            coordinate.$1,
            coordinate.$2,
            iterations,
            bailout,
            juliaC,
          );
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (ty * w + tx) * 4;
      bytes[idx + 0] = (rAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return bytes;
}

import 'dart:async';
import 'dart:isolate';

import 'cpu_render_isolate.dart';

/// A long-lived isolate for CPU tile rendering.
///
/// Spawning an isolate per tile (Isolate.run) is far too slow on mobile.
/// This worker keeps one isolate alive and processes tile jobs sequentially.
class CpuTileWorker {
  CpuTileWorker._(this._isolate, this._sendPort, this._sub);

  final Isolate _isolate;
  final SendPort _sendPort;
  final StreamSubscription _sub;

  static Future<CpuTileWorker> spawn() async {
    final receive = ReceivePort();
    final handshake = Completer<SendPort>();

    final sub = receive.listen((msg) {
      if (msg is SendPort && !handshake.isCompleted) {
        handshake.complete(msg);
      }
    });

    final isolate = await Isolate.spawn(_entry, receive.sendPort);
    final sendPort = await handshake.future;

    return CpuTileWorker._(isolate, sendPort, sub);
  }

  Future<CpuTileRenderResponse> renderTile(CpuTileRenderRequest req) async {
    final rp = ReceivePort();
    _sendPort.send((req, rp.sendPort));
    final msg = await rp.first;
    rp.close();
    return msg as CpuTileRenderResponse;
  }

  void dispose() {
    _sub.cancel();
    _isolate.kill(priority: Isolate.immediate);
  }
}

void _entry(SendPort mainSendPort) {
  final commands = ReceivePort();
  mainSendPort.send(commands.sendPort);

  commands.listen((msg) {
    final (CpuTileRenderRequest req, SendPort replyTo) = msg as (CpuTileRenderRequest, SendPort);
    final resp = renderCpuTileInIsolate(req);
    replyTo.send(resp);
  });
}

// CPU iterator/escape metric registry.
//
// Goal: allow palette-independent quality audits and future CPU-vs-GPU
// correctness checks by exposing per-pixel escape/iteration metrics.
//
// IMPORTANT:
// - For classic escape-time sets we provide true escape iterations.
// - For the broader catalog (many non-escape/IFS/attractor/CA shaders), we
//   currently provide a deterministic *proxy iterator* derived from the CPU
//   formula color output. This still decouples the audit from RGB variance
//   thresholds and gives us a stable scalar field to score structure.
//   We can replace proxies with true iteration metrics module-by-module over
//   time.

import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';

final class CpuIteratorResult {
  const CpuIteratorResult({
    required this.it,
    required this.smoothIt,
    required this.escaped,
  });

  /// Integer iteration count (0..iterations). iterations means "inside".
  final int it;

  /// Optional smooth/continuous iteration value.
  final double smoothIt;

  /// True if escaped (it < iterations).
  final bool escaped;
}

typedef CpuIterator = CpuIteratorResult Function(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
);

/// Primary iterator registry.
final Map<String, CpuIterator> cpuIteratorsByModuleId = <String, CpuIterator>{
  'mandelbrot': _iterMandelbrot,
  'burning_ship': _iterBurningShip,
  'tricorn': _iterTricorn,
  'julia': _iterJulia,
  'multibrot4': _iterMultibrot4,
  'multibrot5': _iterMultibrot5,
  'phoenix': _iterPhoenix,

  // Start with the 30 modules that were GRADIENT_ONLY in the audit.
  // For many of these modules the shader/CPU path is not a classic escape-time
  // recurrence, so we use a deterministic proxy iterator derived from the
  // existing CPU formula’s scalar luminance.
  'astroid': _proxyFromColor('astroid'),
  'deltoid': _iterDeltoid,
  'eisenstein': _iterEisenstein,
  'barnsley_fern': _proxyFromColor('barnsley_fern'),
  'hilbert_curve': _proxyFromColor('hilbert_curve'),
  'penrose_tiling': _proxyFromColor('penrose_tiling'),
  'hexaflake': _proxyFromColor('hexaflake'),
  'tinkerbell': _proxyFromColor('tinkerbell'),
  'gingerbreadman': _proxyFromColor('gingerbreadman'),
  'peter_de_jong': _proxyFromColor('peter_de_jong'),
  'arnold_cat': _proxyFromColor('arnold_cat'),
  'arneodo': _proxyFromColor('arneodo'),
  'halvorsen': _proxyFromColor('halvorsen'),
  'moore_spiegel': _proxyFromColor('moore_spiegel'),
  'genesio_tesi': _proxyFromColor('genesio_tesi'),
  'bouali': _proxyFromColor('bouali'),
  'buffalo_julia': _proxyFromColor('buffalo_julia'),
  'perpendicular_julia': _proxyFromColor('perpendicular_julia'),
  'cosine_mandelbrot': _proxyFromColor('cosine_mandelbrot'),
  'lyapunov': _proxyFromColor('lyapunov'),
  'logistic_lyapunov': _proxyFromColor('logistic_lyapunov'),
  'feigenbaum': _proxyFromColor('feigenbaum'),
  'buddhabrot_approx': _proxyFromColor('buddhabrot_approx'),
  'anti_buddhabrot': _proxyFromColor('anti_buddhabrot'),
  'wolfram_rule30': _proxyFromColor('wolfram_rule30'),
  'turmite': _proxyFromColor('turmite'),
  'eden_growth': _proxyFromColor('eden_growth'),
  'moore_curve': _proxyFromColor('moore_curve'),
  'spider_x': _proxyFromColor('spider_x'),
  'hat_monotile': _proxyFromColor('hat_monotile'),
};

CpuIterator proxyIteratorForModule(String moduleId) {
  return cpuIteratorsByModuleId[moduleId] ?? _proxyFromColor(moduleId);
}

CpuIterator _proxyFromColor(String moduleId) {
  final seed = _fnv1a32(moduleId);
  return (x, y, iterations, bailout, juliaC) {
    final f = cpuFormulaForModuleId(moduleId);
    final c = f(x, y, iterations, bailout, juliaC);

    // Proxy scalar from color.
    final lum =
        (0.2126 * c.$1 + 0.7152 * c.$2 + 0.0722 * c.$3).clamp(0.0, 255.0);
    var it = ((lum / 255.0) * iterations).floor().clamp(0, iterations);

    // If the CPU formula returns a very flat color field (common for "synthetic"
    // placeholder modules), luminance quantization can collapse to a constant.
    // Mix in a tiny, deterministic spatial hash so audits still detect structure.
    final xi = (x * 1e6).round();
    final yi = (y * 1e6).round();
    final h = _mix32(seed ^ (xi * 374761393) ^ (yi * 668265263));
    it = (it ^ (h & 0x0F)).clamp(0, iterations);

    return CpuIteratorResult(
        it: it, smoothIt: it.toDouble(), escaped: it < iterations);
  };
}

CpuIteratorResult _iterMandelbrot(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = 2.0 * zx * zy + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterBurningShip(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final ax = zx.abs();
    final ay = zy.abs();
    final zx2 = ax * ax;
    final zy2 = ay * ay;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = 2.0 * ax * ay + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterTricorn(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = -2.0 * zx * zy + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterJulia(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = x;
  double zy = y;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + juliaC.x;
    final ny = 2.0 * zx * zy + juliaC.y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterMultibrot4(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z4x = z2x * z2x - z2y * z2y;
    final z4y = 2.0 * z2x * z2y;
    zx = z4x + x;
    zy = z4y + y;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterMultibrot5(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z4x = z2x * z2x - z2y * z2y;
    final z4y = 2.0 * z2x * z2y;
    final z5x = z4x * zx - z4y * zy;
    final z5y = z4x * zy + z4y * zx;
    zx = z5x + x;
    zy = z5y + y;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterPhoenix(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Stable CPU default for p matches phoenix module default.
  const p = -0.5;

  double zx = x;
  double zy = y;
  double zPrevX = 0.0;
  double zPrevY = 0.0;

  final cx = juliaC.x;
  final cy = juliaC.y;
  final bailout2 = bailout * bailout;

  int it = 0;
  while (it < iterations) {
    final nx = zx * zx - zy * zy + cx + p * zPrevX;
    final ny = 2.0 * zx * zy + cy + p * zPrevY;

    zPrevX = zx;
    zPrevY = zy;
    zx = nx;
    zy = ny;

    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterDeltoid(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Matches cpu_formulas.dart (ported from shaders/escape_time_family/polynomial_maps/fractional_and_folded/deltoid_gpu.frag)
  final cx = x;
  final cy = y;
  // Start z at c; starting at 0 makes z=0 a fixed point for this recurrence.
  double zx = cx;
  double zy = cy;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final czx = cx * zx + cy * zy;
    final czy = cy * zx - cx * zy;
    zx = z2x + czx;
    zy = z2y + czy;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterEisenstein(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Matches cpu_formulas.dart (ported from shaders/escape_time_family/polynomial_maps/lattice_wrapped/eisenstein_gpu.frag)
  const sqrt3 = 1.7320508075688772;
  final cx = x;
  final cy = y;
  double zx = 0.0;
  double zy = 0.0;

  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z3x = z2x * zx - z2y * zy + cx;
    final z3y = z2x * zy + z2y * zx + cy;

    final rawMag2 = z3x * z3x + z3y * z3y;
    if (rawMag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: rawMag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final r = (2.0 * z3y) / sqrt3;
    final q = z3x - z3y / sqrt3;
    final rq = (q + 0.5).floorToDouble();
    final rr = (r + 0.5).floorToDouble();

    final lattX = rq + 0.5 * rr;
    final lattY = 0.5 * sqrt3 * rr;
    zx = z3x - lattX;
    zy = z3y - lattY;

    if (zx * zx + zy * zy > bailout2 * 0.25) {
      final m2 = zx * zx + zy * zy;
      final smooth = _smoothEscape(it: it, mag2: m2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

int _fnv1a32(String s) {
  int h = 0x811c9dc5;
  for (final cu in s.codeUnits) {
    h ^= cu;
    h = (h * 0x01000193) & 0xFFFFFFFF;
  }
  return h;
}

int _mix32(int x) {
  x &= 0xFFFFFFFF;
  x ^= (x >> 16);
  x = (x * 0x7feb352d) & 0xFFFFFFFF;
  x ^= (x >> 15);
  x = (x * 0x846ca68b) & 0xFFFFFFFF;
  x ^= (x >> 16);
  return x & 0xFFFFFFFF;
}

double _smoothEscape(
    {required int it, required double mag2, required double bailout}) {
  // Standard continuous potential smoothing.
  // nu = log(log(|z|))/log(2)
  final r = math.sqrt(mag2);
  final nu =
      math.log(math.max(1e-9, math.log(math.max(r, bailout)))) / math.ln2;
  return it + 1.0 - nu;
}

import 'dart:typed_data';
import 'dart:math' as math;

/// Result of convergence detection analysis.
class ConvergenceChangeRatio {
  static const double equalityTolerance = 1e-9;

  const ConvergenceChangeRatio._();

  static bool approximatelyEqual(double a, double b) =>
      (a - b).abs() < equalityTolerance;
}

class ConvergenceResult {
  /// Whether the image has converged (stabilized).
  final bool converged;

  /// The ratio of pixels that changed between frames (0.0 to 1.0).
  final double changeRatio;

  /// Suggested number of iterations for the next render.
  final int suggestedIterations;

  const ConvergenceResult({
    required this.converged,
    required this.changeRatio,
    required this.suggestedIterations,
  });

  @override
  String toString() {
    return 'ConvergenceResult(converged: $converged, '
        'changeRatio: ${changeRatio.toStringAsFixed(6)}, '
        'suggestedIterations: $suggestedIterations)';
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is ConvergenceResult &&
        other.converged == converged &&
        ConvergenceChangeRatio.approximatelyEqual(
          other.changeRatio,
          changeRatio,
        ) &&
        other.suggestedIterations == suggestedIterations;
  }

  @override
  int get hashCode => Object.hash(converged, suggestedIterations);
}

/// Replayable frame shape contract for convergence comparison.
class ConvergenceFrameSpec {
  final int width;
  final int height;

  const ConvergenceFrameSpec({
    required this.width,
    required this.height,
  });

  int get expectedRgbaLength => width * height * 4;

  void validateBuffers({
    required Uint8List previous,
    required Uint8List current,
  }) {
    if (width <= 0 || height <= 0) {
      throw ArgumentError('Invalid dimensions: ${width}x$height');
    }

    if (previous.length != current.length) {
      throw ArgumentError(
        'Buffer size mismatch: previous=${previous.length}, current=${current.length}',
      );
    }

    if (previous.length != expectedRgbaLength) {
      throw ArgumentError(
        'Buffer size mismatch: expected=$expectedRgbaLength (${width}x$height RGBA), '
        'got=${previous.length}',
      );
    }
  }
}

/// Replayable downsampling grid for convergence comparison.
class ConvergenceSamplingPlan {
  /// Integer stride used to sample the original frame.
  final int factor;

  /// Width of the sampled comparison grid.
  final int sampledWidth;

  /// Height of the sampled comparison grid.
  final int sampledHeight;

  const ConvergenceSamplingPlan._({
    required this.factor,
    required this.sampledWidth,
    required this.sampledHeight,
  });

  factory ConvergenceSamplingPlan({
    required int width,
    required int height,
    required int target,
  }) {
    if (width <= 0 || height <= 0) {
      throw ArgumentError('Invalid dimensions: ${width}x$height');
    }
    if (target <= 0) {
      throw ArgumentError('Invalid downsampleTarget: $target');
    }

    final maxDimension = math.max(width, height);
    final factor = math.max(1, (maxDimension / target).ceil());
    return ConvergenceSamplingPlan._(
      factor: factor,
      sampledWidth: (width / factor).ceil(),
      sampledHeight: (height / factor).ceil(),
    );
  }
}

/// Replayable threshold contract for RGB pixel-change comparison.
class ConvergencePixelChangeRule {
  final int threshold;

  const ConvergencePixelChangeRule(this.threshold);

  void validate() {
    if (threshold < 0) {
      throw ArgumentError('Invalid pixelDifferenceThreshold: $threshold');
    }
  }

  bool sampleChanged({
    required Uint8List previous,
    required Uint8List current,
    required int pixelIndex,
  }) {
    for (int channel = 0; channel < 3; channel++) {
      final diff =
          (previous[pixelIndex + channel] - current[pixelIndex + channel])
              .abs();
      if (diff > threshold) return true;
    }
    return false;
  }
}

/// Replayable count summary for one convergence comparison.
class ConvergenceComparisonStats {
  final int changedPixels;
  final int totalPixels;

  const ConvergenceComparisonStats({
    required this.changedPixels,
    required this.totalPixels,
  })  : assert(changedPixels >= 0, 'changedPixels must be non-negative'),
        assert(totalPixels >= 0, 'totalPixels must be non-negative'),
        assert(
          changedPixels <= totalPixels,
          'changedPixels must not exceed totalPixels',
        );

  double get changeRatio => totalPixels > 0 ? changedPixels / totalPixels : 0.0;
}

/// Replayable iteration recommendation for convergence results.
class ConvergenceIterationRecommendation {
  const ConvergenceIterationRecommendation._();

  static int forChangeRatio({
    required double changeRatio,
    required int currentIterations,
  }) {
    if (currentIterations <= 0) {
      throw ArgumentError('Invalid currentIterations: $currentIterations');
    }

    if (changeRatio > ConvergenceDetector.changeThreshold) {
      return (currentIterations * ConvergenceDetector.iterationMultiplier)
          .round();
    }
    return currentIterations;
  }
}

/// Detects convergence between two rendered frames to enable adaptive iteration refinement.
///
/// Compares two RGBA frame buffers and determines if the rendering has stabilized.
/// Uses downsampling to ~64x64 resolution for performance.
class ConvergenceDetector {
  /// Threshold for considering a pixel as "changed" (per channel, 0-255).
  final int pixelDifferenceThreshold;

  /// Target downsample resolution for comparison (approximate).
  final int downsampleTarget;

  /// Convergence threshold: below this ratio, the image is considered converged.
  static const double convergenceThreshold = 0.001;

  /// Change threshold: above this ratio, suggest increasing iterations.
  static const double changeThreshold = 0.01;

  /// Multiplier for suggested iterations when image hasn't converged.
  static const double iterationMultiplier = 1.5;

  const ConvergenceDetector({
    this.pixelDifferenceThreshold = 5,
    this.downsampleTarget = 64,
  });

  /// Compares two RGBA frame buffers and returns convergence analysis.
  ///
  /// [previous] and [current] must be RGBA Uint8List buffers of identical dimensions.
  /// [width] and [height] are the original buffer dimensions in pixels.
  /// [currentIterations] is the iteration count used to render [current].
  ///
  /// Returns a [ConvergenceResult] indicating whether the image has converged,
  /// the change ratio, and suggested iterations for the next render.
  ConvergenceResult detect({
    required Uint8List previous,
    required Uint8List current,
    required int width,
    required int height,
    required int currentIterations,
  }) {
    ConvergenceFrameSpec(width: width, height: height).validateBuffers(
      previous: previous,
      current: current,
    );
    if (currentIterations <= 0) {
      throw ArgumentError('Invalid currentIterations: $currentIterations');
    }

    final stats = compareFrames(
      previous: previous,
      current: current,
      width: width,
      height: height,
    );
    final changeRatio = stats.changeRatio;

    return ConvergenceResult(
      converged: changeRatio < convergenceThreshold,
      changeRatio: changeRatio,
      suggestedIterations: ConvergenceIterationRecommendation.forChangeRatio(
        changeRatio: changeRatio,
        currentIterations: currentIterations,
      ),
    );
  }

  /// Returns replayable comparison counts before policy thresholds are applied.
  ConvergenceComparisonStats compareFrames({
    required Uint8List previous,
    required Uint8List current,
    required int width,
    required int height,
  }) {
    final frameSpec = ConvergenceFrameSpec(width: width, height: height);
    frameSpec.validateBuffers(previous: previous, current: current);

    final pixelChangeRule = ConvergencePixelChangeRule(
      pixelDifferenceThreshold,
    );
    pixelChangeRule.validate();

    final samplingPlan = ConvergenceSamplingPlan(
      width: width,
      height: height,
      target: downsampleTarget,
    );

    int changedPixels = 0;
    int totalPixels = 0;

    for (int y = 0; y < samplingPlan.sampledHeight; y++) {
      for (int x = 0; x < samplingPlan.sampledWidth; x++) {
        final srcX = (x * samplingPlan.factor).clamp(0, width - 1);
        final srcY = (y * samplingPlan.factor).clamp(0, height - 1);
        final pixelIndex = (srcY * width + srcX) * 4;

        if (pixelChangeRule.sampleChanged(
          previous: previous,
          current: current,
          pixelIndex: pixelIndex,
        )) {
          changedPixels++;
        }
        totalPixels++;
      }
    }

    return ConvergenceComparisonStats(
      changedPixels: changedPixels,
      totalPixels: totalPixels,
    );
  }
}

import 'dart:typed_data';
import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/features/renderer/convergence_detector.dart';

void main() {
  group('ConvergenceResult', () {
    test('hashCode is compatible with approximate changeRatio equality', () {
      const base = ConvergenceResult(
        converged: true,
        changeRatio: 0.123456789,
        suggestedIterations: 100,
      );
      const approximatelyEqual = ConvergenceResult(
        converged: true,
        changeRatio: 0.1234567895,
        suggestedIterations: 100,
      );

      expect(base, approximatelyEqual);
      expect(base.hashCode, approximatelyEqual.hashCode);
      expect({base}, contains(approximatelyEqual));
    });
  });

  group('ConvergenceComparisonStats', () {
    test('exposes replayable change ratio from sampled counts', () {
      const stats = ConvergenceComparisonStats(
        changedPixels: 2,
        totalPixels: 8,
      );

      expect(stats.changeRatio, 0.25);
    });
  });

  group('ConvergenceIterationRecommendation', () {
    test('keeps iterations for minor changes and rejects invalid counts', () {
      expect(
        ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: ConvergenceDetector.changeThreshold,
          currentIterations: 100,
        ),
        100,
      );
      expect(
        () => ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: 0.0,
          currentIterations: 0,
        ),
        throwsArgumentError,
      );
    });

    test('increases iterations above the significant-change threshold', () {
      expect(
        ConvergenceIterationRecommendation.forChangeRatio(
          changeRatio: ConvergenceDetector.changeThreshold + 0.001,
          currentIterations: 100,
        ),
        150,
      );
    });
  });

  group('ConvergenceSamplingPlan', () {
    test('keeps sampling grid dimensions replayable for non-square frames', () {
      final plan = ConvergenceSamplingPlan(width: 130, height: 65, target: 64);

      expect(plan.factor, 3);
      expect(plan.sampledWidth, 44);
      expect(plan.sampledHeight, 22);
    });

    test('rejects invalid downsample target before comparing frames', () {
      expect(
        () => ConvergenceSamplingPlan(width: 64, height: 64, target: 0),
        throwsArgumentError,
      );
    });
  });

  group('ConvergenceDetector', () {
    const detector = ConvergenceDetector();

    test('compareFrames exposes sampled counts before convergence policy', () {
      final previous = Uint8List(4 * 4 * 4);
      final current = Uint8List.fromList(previous);
      current[0] = 10;
      current[(3 * 4 + 3) * 4] = 10;

      final stats = detector.compareFrames(
        previous: previous,
        current: current,
        width: 4,
        height: 4,
      );

      expect(stats.changedPixels, 2);
      expect(stats.totalPixels, 16);
      expect(stats.changeRatio, 0.125);
    });

    test('compareFrames ignores alpha-only changes', () {
      final previous = Uint8List(4 * 4 * 4);
      final current = Uint8List.fromList(previous);
      current[3] = 255;

      final stats = detector.compareFrames(
        previous: previous,
        current: current,
        width: 4,
        height: 4,
      );

      expect(stats.changedPixels, 0);
      expect(stats.changeRatio, 0.0);
    });

    test('detects identical frames as converged', () {
      final buffer =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => i % 256));

      final result = detector.detect(
        previous: buffer,
        current: buffer,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      expect(result.converged, isTrue);
      expect(result.changeRatio, closeTo(0.0, 0.001));
    });

    test('detects different frames as not converged', () {
      // Need to change by more than threshold (5) per channel.
      final previous =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => i % 256));
      final current =
          Uint8List.fromList(List.generate(64 * 64 * 4, (i) => (i + 10) % 256));

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // With 100% pixel change, definitely not converged.
      expect(result.converged, isFalse);
      expect(result.changeRatio, greaterThan(0.5));
    });

    test('suggests increased iterations for significantly changed frames', () {
      // Create 5% pixel change (above 1% threshold).
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List.fromList(previous);
      for (int i = 0; i < 64 * 64 * 4; i += 20) {
        current[i] = (current[i] + 10) % 256;
      }

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // 5% change > 1% threshold should suggest more iterations.
      expect(result.suggestedIterations, greaterThan(100));
    });

    test('throws domain error for invalid downsample target', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(64 * 64 * 4);
      const invalidDetector = ConvergenceDetector(downsampleTarget: 0);

      expect(
        () => invalidDetector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('throws domain error for negative pixel difference threshold', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(64 * 64 * 4);
      const invalidDetector = ConvergenceDetector(pixelDifferenceThreshold: -1);

      expect(
        () => invalidDetector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('throws on buffer size mismatch', () {
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List(32 * 32 * 4);

      expect(
        () => detector.detect(
          previous: previous,
          current: current,
          width: 64,
          height: 64,
          currentIterations: 100,
        ),
        throwsArgumentError,
      );
    });

    test('handles small change ratios below convergence threshold', () {
      // The convergence threshold is 0.1% - change fewer than that.
      final previous = Uint8List(64 * 64 * 4);
      final current = Uint8List.fromList(previous);
      // Change only 0.05% of pixels.
      for (int i = 0; i < 64 * 64 * 4; i += 2000) {
        current[i] = (current[i] + 10) % 256;
      }

      final result = detector.detect(
        previous: previous,
        current: current,
        width: 64,
        height: 64,
        currentIterations: 100,
      );

      // Very small changes (0.05%) should be below 0.1% threshold.
      expect(result.changeRatio, lessThan(0.005));
    });
  });
}

import 'dart:async';

import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

/// Parsed deep link data containing fractal configuration.
///
/// This class represents the configuration extracted from a deep link URL
/// like `fractalforge://view?type=mandelbrot&zoom=10&x=0.5`.
///
/// {@category Services}
class DeepLinkData {
  /// The fractal module ID (e.g., 'mandelbrot', 'julia', 'mandelbulb').
  final String type;

  /// Zoom level (magnification).
  final double? zoom;

  /// Pan X coordinate (2D fractals).
  final double? x;

  /// Pan Y coordinate (2D fractals).
  final double? y;

  /// Rotation X angle in radians (3D fractals).
  final double? rotX;

  /// Rotation Y angle in radians (3D fractals).
  final double? rotY;

  /// Rotation Z angle in radians (3D fractals).
  final double? rotZ;

  /// Number of iterations.
  final int? iterations;

  /// Bailout radius.
  final double? bailout;

  /// Color scheme index.
  final int? colorScheme;

  /// Power parameter (for fractals like Mandelbulb).
  final double? power;

  /// Julia set real constant (c.x).
  final double? juliaX;

  /// Julia set imaginary constant (c.y).
  final double? juliaY;

  const DeepLinkData({
    required this.type,
    this.zoom,
    this.x,
    this.y,
    this.rotX,
    this.rotY,
    this.rotZ,
    this.iterations,
    this.bailout,
    this.colorScheme,
    this.power,
    this.juliaX,
    this.juliaY,
  });

  /// Creates a [FractalViewState] from the parsed deep link data.
  FractalViewState toViewState() {
    return FractalViewState(
      pan: Vector2(x ?? 0.0, y ?? 0.0),
      zoom: zoom ?? 1.0,
      rotation: Vector3(rotX ?? 0.0, rotY ?? 0.0, rotZ ?? 0.0),
    );
  }

  /// Extracts fractal parameters from the deep link data.
  ///
  /// Returns a map of parameter IDs to values.
  Map<String, Object> toParams() {
    final params = <String, Object>{};

    if (iterations != null) params['iterations'] = iterations!;
    if (bailout != null) params['bailout'] = bailout!;
    if (colorScheme != null) params['colorScheme'] = colorScheme!;
    if (power != null) params['power'] = power!;
    if (juliaX != null) params['juliaX'] = juliaX!;
    if (juliaY != null) params['juliaY'] = juliaY!;

    return params;
  }

  @override
  String toString() {
    return 'DeepLinkData(type: $type, zoom: $zoom, x: $x, y: $y, '
        'rotX: $rotX, rotY: $rotY, rotZ: $rotZ, iterations: $iterations, '
        'bailout: $bailout, colorScheme: $colorScheme, power: $power, '
        'juliaX: $juliaX, juliaY: $juliaY)';
  }
}

/// Service for handling deep links with the `fractalforge://` scheme.
///
/// Supports URLs like:
/// - `fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1`
/// - `fractalforge://view?type=julia&juliaX=-0.7&juliaY=0.27&colorScheme=2`
/// - `fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&power=8`
///
/// {@category Services}
class _DeepLinkRoute {
  static const allowedWebHosts = {'fractalforge.app', 'www.fractalforge.app'};

  final bool isAccepted;

  const _DeepLinkRoute._(this.isAccepted);

  factory _DeepLinkRoute.fromUri(Uri uri) {
    if (uri.scheme == DeepLinkService.scheme) {
      return _DeepLinkRoute._(_isCustomViewRoute(uri));
    }

    if (uri.scheme == 'https') {
      return _DeepLinkRoute._(
        allowedWebHosts.contains(uri.host) && _isWebViewRoute(uri),
      );
    }

    return const _DeepLinkRoute._(false);
  }

  static bool _isCustomViewRoute(Uri uri) {
    return uri.host == DeepLinkService.host ||
        uri.path == '/${DeepLinkService.host}' ||
        uri.path == DeepLinkService.host;
  }

  static bool _isWebViewRoute(Uri uri) {
    return uri.path == '/${DeepLinkService.host}';
  }
}

class _DeepLinkModuleId {
  static final RegExp _safePattern = RegExp(r'^[a-z0-9_]+$');

  const _DeepLinkModuleId._();

  static bool isSafe(String moduleId) => _safePattern.hasMatch(moduleId);

  static String requireSafeForBuild(String moduleId) {
    if (!isSafe(moduleId)) {
      throw ArgumentError.value(
        moduleId,
        'moduleId',
        'Deep-link module IDs must match ${_safePattern.pattern}',
      );
    }
    return moduleId;
  }
}

class _DeepLinkQuery {
  static const recognizedNames = {
    'type',
    'zoom',
    'x',
    'y',
    'rotX',
    'rotY',
    'rotZ',
    'iterations',
    'bailout',
    'colorScheme',
    'power',
    'juliaX',
    'juliaY',
  };

  final Map<String, String> _params;

  const _DeepLinkQuery._(this._params);

  factory _DeepLinkQuery.fromUri(Uri uri) {
    final duplicatedRecognizedKeys = uri.queryParametersAll.entries.where(
      (entry) => recognizedNames.contains(entry.key) && entry.value.length > 1,
    );
    if (duplicatedRecognizedKeys.isNotEmpty) {
      throw FormatException(
        'Duplicate deep-link query parameter: '
        '${duplicatedRecognizedKeys.first.key}',
      );
    }

    return _DeepLinkQuery._(uri.queryParameters);
  }

  String? operator [](String name) => _params[name];
}

class _BoundedDoubleQueryParam {
  final String name;
  final double min;
  final double max;

  const _BoundedDoubleQueryParam(this.name, this.min, this.max);

  double? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedDouble(query[name], min, max, name);
  }

  String? format(Object? value, {bool preservePrecision = false}) {
    final parsed = DeepLinkService._tryFiniteDouble(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return DeepLinkService._formatDouble(
      parsed,
      preservePrecision: preservePrecision,
    );
  }

  bool _contains(double value) => value >= min && value <= max;
}

class _BoundedIntQueryParam {
  final String name;
  final int min;
  final int max;

  const _BoundedIntQueryParam(this.name, this.min, this.max);

  int? parse(_DeepLinkQuery query) {
    return DeepLinkService._parseBoundedInt(query[name], min, max, name);
  }

  String? format(Object? value) {
    final parsed = DeepLinkService._tryInt(value);
    if (parsed == null || !_contains(parsed)) {
      return null;
    }
    return parsed.toString();
  }

  bool _contains(int value) => value >= min && value <= max;
}

class DeepLinkService {
  static const String scheme = 'fractalforge';
  static const String host = 'view';

  static const _zoomParam = _BoundedDoubleQueryParam('zoom', 0.001, 1e15);
  static const _xParam = _BoundedDoubleQueryParam('x', -1e10, 1e10);
  static const _yParam = _BoundedDoubleQueryParam('y', -1e10, 1e10);
  static const _rotXParam = _BoundedDoubleQueryParam('rotX', -1e10, 1e10);
  static const _rotYParam = _BoundedDoubleQueryParam('rotY', -1e10, 1e10);
  static const _rotZParam = _BoundedDoubleQueryParam('rotZ', -1e10, 1e10);
  static const _iterationsParam = _BoundedIntQueryParam('iterations', 1, 10000);
  static const _bailoutParam = _BoundedDoubleQueryParam('bailout', 1.0, 1e10);
  static const _colorSchemeParam =
      _BoundedIntQueryParam('colorScheme', 0, 9999);
  static const _powerParam = _BoundedDoubleQueryParam('power', 1, 20);
  static const _juliaXParam = _BoundedDoubleQueryParam('juliaX', -1e10, 1e10);
  static const _juliaYParam = _BoundedDoubleQueryParam('juliaY', -1e10, 1e10);

  // Method channel for receiving deep links from native code
  static const MethodChannel _channel =
      MethodChannel('com.fractalforge/deeplink');

  final StreamController<DeepLinkData> _linkController =
      StreamController<DeepLinkData>.broadcast();

  /// Stream of parsed deep link data.
  Stream<DeepLinkData> get linkStream => _linkController.stream;

  DeepLinkData? _initialLink;

  /// The initial deep link that launched the app (if any).
  DeepLinkData? get initialLink => _initialLink;

  /// Initializes the deep link service.
  ///
  /// Sets up listeners for incoming deep links from the platform.
  Future<void> initialize() async {
    // TEMPORARY SAFETY SWITCH (2026-02): deep link channel init causes a black screen
    // on some Samsung S24 devices during startup.
    // User confirmed deep links are not needed for the immediate release.
    // We leave parsing + stream support intact for later re-enable.
    const bool kEnableDeepLinks =
        bool.fromEnvironment('ENABLE_DEEP_LINKS', defaultValue: false);
    if (!kEnableDeepLinks) {
      return;
    }

    // Set up method channel handler for incoming links
    _channel.setMethodCallHandler(_handleMethodCall);

    // Try to get the initial link that launched the app
    try {
      final String? initialUri = await _channel.invokeMethod('getInitialLink');
      if (initialUri != null) {
        try {
          final uri = Uri.parse(initialUri);
          final data = parseUri(uri);
          if (data != null) {
            _initialLink = data;
          }
        } catch (e) {
          // Malformed URI, ignore
          if (kDebugMode)
            debugPrint('Failed to parse initial deep link URI: $e');
        }
      }
    } on PlatformException {
      // Platform doesn't support deep links or no initial link
    }
  }

  Future<dynamic> _handleMethodCall(MethodCall call) async {
    if (call.method == 'onDeepLink') {
      final String uriString = call.arguments as String;
      try {
        final uri = Uri.parse(uriString);
        final data = parseUri(uri);
        if (data != null) {
          _linkController.add(data);
        }
      } catch (e) {
        // Malformed URI, ignore
        if (kDebugMode) debugPrint('Failed to parse deep link URI: $e');
      }
    }
  }

  /// Parses a URI into [DeepLinkData].
  ///
  /// Returns null if the URI is not a valid fractalforge deep link or
  /// if the fractal type is not recognized.
  static DeepLinkData? parseUri(Uri uri, {List<String>? validFractalTypes}) {
    final route = _DeepLinkRoute.fromUri(uri);
    if (!route.isAccepted) {
      return null;
    }

    final _DeepLinkQuery query;
    try {
      query = _DeepLinkQuery.fromUri(uri);
    } on FormatException catch (e) {
      if (kDebugMode) debugPrint('DeepLink: ${e.message} — rejecting link');
      return null;
    }

    final type = query['type'];

    if (type == null || type.isEmpty) {
      return null;
    }

    // Reject type strings with unsafe characters (defense-in-depth).
    if (!_DeepLinkModuleId.isSafe(type)) {
      return null;
    }

    // Validate fractal type if validation list provided
    if (validFractalTypes != null && !validFractalTypes.contains(type)) {
      return null;
    }

    return DeepLinkData(
      type: type,
      zoom: _zoomParam.parse(query),
      x: _xParam.parse(query),
      y: _yParam.parse(query),
      rotX: _rotXParam.parse(query),
      rotY: _rotYParam.parse(query),
      rotZ: _rotZParam.parse(query),
      iterations: _iterationsParam.parse(query),
      bailout: _bailoutParam.parse(query),
      colorScheme: _colorSchemeParam.parse(query),
      power: _powerParam.parse(query),
      juliaX: _juliaXParam.parse(query),
      juliaY: _juliaYParam.parse(query),
    );
  }

  /// Builds a shareable deep link URL from the current fractal state.
  ///
  /// The [moduleId] specifies the fractal type, [params] contains the
  /// fractal parameters, and [view] contains the camera/view state.
  static Uri buildUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final queryParams = <String, String>{
      'type': _DeepLinkModuleId.requireSafeForBuild(moduleId),
    };

    // Add view state. Use the same bounded contracts as parsing so generated
    // links do not round-trip through clamped or invalid camera values.
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _zoomParam,
      view.zoom,
      defaultValue: 1.0,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _xParam,
      view.pan.x,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
      queryParams,
      _yParam,
      view.pan.y,
      preservePrecision: true,
    );
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotXParam, view.rotation.x);
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotYParam, view.rotation.y);
    _addNonDefaultBoundedDoubleQueryParam(
        queryParams, _rotZParam, view.rotation.z);

    // Add fractal parameters. Unsupported values are omitted rather than
    // converted to sentinel values that parse back as valid-but-wrong params.
    _addBoundedIntQueryParam(
        queryParams, _iterationsParam, params['iterations']);
    _addBoundedDoubleQueryParam(queryParams, _bailoutParam, params['bailout']);
    _addBoundedIntQueryParam(
      queryParams,
      _colorSchemeParam,
      params['colorScheme'],
    );
    _addBoundedDoubleQueryParam(queryParams, _powerParam, params['power']);
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaXParam,
      params['juliaX'],
      preservePrecision: true,
    );
    _addBoundedDoubleQueryParam(
      queryParams,
      _juliaYParam,
      params['juliaY'],
      preservePrecision: true,
    );

    return Uri(
      scheme: scheme,
      host: host,
      queryParameters: queryParams,
    );
  }

  /// Builds a web-compatible URL for sharing.
  ///
  /// Uses a hypothetical web domain for universal link support.
  static Uri buildWebUri({
    required String moduleId,
    required Map<String, Object> params,
    required FractalViewState view,
  }) {
    final customUri = buildUri(moduleId: moduleId, params: params, view: view);
    return Uri(
      scheme: 'https',
      host: 'fractalforge.app',
      path: '/view',
      queryParameters: customUri.queryParameters,
    );
  }

  static double? _parseBoundedDouble(
      String? v, double min, double max, String paramName) {
    if (v == null) return null;
    final d = double.tryParse(v);
    if (d == null || d.isNaN || d.isInfinite) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = d.clamp(min, max);
    if (clamped != d) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $d out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static int? _parseBoundedInt(String? v, int min, int max, String paramName) {
    if (v == null) return null;
    final i = int.tryParse(v);
    if (i == null) {
      if (kDebugMode)
        debugPrint('DeepLink: invalid value for "$paramName": "$v" — ignoring');
      return null;
    }
    final clamped = i.clamp(min, max);
    if (clamped != i) {
      if (kDebugMode)
        debugPrint(
            'DeepLink: "$paramName" value $i out of [$min, $max] — clamped to $clamped');
    }
    return clamped;
  }

  static String _formatDouble(
    double value, {
    bool preservePrecision = false,
  }) {
    // Keep integer-looking values compact without truncating significant deep-zoom
    // view coordinates that need more than six decimal places to round-trip.
    if (value == value.truncateToDouble()) {
      return value.toInt().toString();
    }

    final compactFixed =
        value.toStringAsFixed(6).replaceAll(RegExp(r'\.?0+$'), '');
    if (!preservePrecision || double.tryParse(compactFixed) == value) {
      return compactFixed;
    }

    return value.toString();
  }

  static void _addBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    bool preservePrecision = false,
  }) {
    final formatted = param.format(
      value,
      preservePrecision: preservePrecision,
    );
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static void _addNonDefaultBoundedDoubleQueryParam(
    Map<String, String> queryParams,
    _BoundedDoubleQueryParam param,
    Object? value, {
    double defaultValue = 0.0,
    bool preservePrecision = false,
  }) {
    final parsed = _tryFiniteDouble(value);
    if (parsed == null || parsed == defaultValue) return;
    _addBoundedDoubleQueryParam(
      queryParams,
      param,
      parsed,
      preservePrecision: preservePrecision,
    );
  }

  static void _addBoundedIntQueryParam(
    Map<String, String> queryParams,
    _BoundedIntQueryParam param,
    Object? value,
  ) {
    final formatted = param.format(value);
    if (formatted != null) {
      queryParams[param.name] = formatted;
    }
  }

  static double? _tryFiniteDouble(Object? value) {
    final parsed = switch (value) {
      double v => v,
      int v => v.toDouble(),
      String v => double.tryParse(v),
      _ => null,
    };
    if (parsed == null || parsed.isNaN || parsed.isInfinite) {
      return null;
    }
    return parsed;
  }

  static int? _tryInt(Object? value) {
    return switch (value) {
      int v => v,
      String v => int.tryParse(v),
      _ => null,
    };
  }

  /// Disposes of the service and closes the stream.
  void dispose() {
    _linkController.close();
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/services/deep_link_service.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:vector_math/vector_math.dart';

void main() {
  group('DeepLinkService', () {
    group('parseUri', () {
      test('parses basic fractalforge:// URL', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
      });

      test('parses URL with zoom and pan parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbrot&zoom=10&x=-0.5&y=0.1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 10.0);
        expect(data.x, -0.5);
        expect(data.y, 0.1);
      });

      test('parses URL with 3D rotation parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbulb&rotX=0.5&rotY=0.3&rotZ=0.1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbulb');
        expect(data.rotX, 0.5);
        expect(data.rotY, 0.3);
        expect(data.rotZ, 0.1);
      });

      test('parses URL with fractal parameters', () {
        final uri = Uri.parse(
            'fractalforge://view?type=julia&iterations=200&colorScheme=2&juliaX=-0.7&juliaY=0.27');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'julia');
        expect(data.iterations, 200);
        expect(data.colorScheme, 2);
        expect(data.juliaX, -0.7);
        expect(data.juliaY, 0.27);
      });

      test('returns null for non-fractalforge scheme', () {
        final uri = Uri.parse('https://example.com/view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('returns null for missing type parameter', () {
        final uri = Uri.parse('fractalforge://view?zoom=10');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('parses https://fractalforge.app universal link', () {
        final uri =
            Uri.parse('https://fractalforge.app/view?type=mandelbrot&zoom=5');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });

      test('rejects https universal links outside the view route', () {
        final uri = Uri.parse(
            'https://fractalforge.app/settings?type=mandelbrot&zoom=5');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('rejects duplicate recognized parameters instead of guessing', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&type=julia&zoom=5',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('rejects duplicate optional parameters instead of truncating', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&zoom=5&zoom=abc',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('ignores duplicate unrecognized parameters', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbrot&utm=a&utm=b&zoom=5',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, 5.0);
      });
    });

    group('buildUri', () {
      test('builds basic URL with type only', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState.initial(),
        );

        expect(uri.scheme, 'fractalforge');
        expect(uri.host, 'view');
        expect(uri.queryParameters['type'], 'mandelbrot');
      });

      test('rejects unsafe module IDs before generating unreplayable links',
          () {
        expect(
          () => DeepLinkService.buildUri(
            moduleId: 'mandelbrot<script>',
            params: const {},
            view: FractalViewState.initial(),
          ),
          throwsArgumentError,
        );
      });

      test('includes zoom when not default', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState(
            pan: Vector2.zero(),
            zoom: 5.0,
            rotation: Vector3.zero(),
          ),
        );

        expect(uri.queryParameters['zoom'], '5');
      });

      test('includes pan coordinates when not zero', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState(
            pan: Vector2(-0.5, 0.25),
            zoom: 1.0,
            rotation: Vector3.zero(),
          ),
        );

        expect(uri.queryParameters['x'], '-0.5');
        expect(uri.queryParameters['y'], '0.25');
      });

      test('includes rotation for 3D fractals', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbulb',
          params: {},
          view: FractalViewState(
            pan: Vector2.zero(),
            zoom: 1.0,
            rotation: Vector3(0.5, 0.3, 0.1),
          ),
        );

        expect(uri.queryParameters['rotX'], '0.5');
        expect(uri.queryParameters['rotY'], '0.3');
        expect(uri.queryParameters['rotZ'], '0.1');
      });

      test('includes fractal parameters', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': 200,
            'colorScheme': 2,
            'bailout': 4.5,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters['iterations'], '200');
        expect(uri.queryParameters['colorScheme'], '2');
        expect(uri.queryParameters['bailout'], '4.5');
      });

      test('omits unsupported parameter values instead of minting fallbacks',
          () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': true,
            'colorScheme': Object(),
            'bailout': 'not-a-number',
            'power': double.nan,
            'juliaX': double.infinity,
            'juliaY': false,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters.containsKey('iterations'), isFalse);
        expect(uri.queryParameters.containsKey('colorScheme'), isFalse);
        expect(uri.queryParameters.containsKey('bailout'), isFalse);
        expect(uri.queryParameters.containsKey('power'), isFalse);
        expect(uri.queryParameters.containsKey('juliaX'), isFalse);
        expect(uri.queryParameters.containsKey('juliaY'), isFalse);
      });

      test('omits out-of-range parameters instead of creating clamped links',
          () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {
            'iterations': 10001,
            'colorScheme': -1,
            'bailout': 0.5,
            'power': 21,
            'juliaX': 10000000001,
            'juliaY': -10000000001,
          },
          view: FractalViewState.initial(),
        );

        expect(uri.queryParameters.containsKey('iterations'), isFalse);
        expect(uri.queryParameters.containsKey('colorScheme'), isFalse);
        expect(uri.queryParameters.containsKey('bailout'), isFalse);
        expect(uri.queryParameters.containsKey('power'), isFalse);
        expect(uri.queryParameters.containsKey('juliaX'), isFalse);
        expect(uri.queryParameters.containsKey('juliaY'), isFalse);
      });

      test(
          'omits invalid view values instead of throwing or minting clamped links',
          () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: const {},
          view: FractalViewState(
            pan: Vector2(double.nan, 1e20),
            zoom: double.infinity,
            rotation: Vector3(double.negativeInfinity, 0.5, -1e20),
          ),
        );

        expect(uri.queryParameters.containsKey('zoom'), isFalse);
        expect(uri.queryParameters.containsKey('x'), isFalse);
        expect(uri.queryParameters.containsKey('y'), isFalse);
        expect(uri.queryParameters.containsKey('rotX'), isFalse);
        expect(uri.queryParameters['rotY'], '0.5');
        expect(uri.queryParameters.containsKey('rotZ'), isFalse);
      });

      test('omits default values for cleaner URLs', () {
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: {},
          view: FractalViewState.initial(),
        );

        // Default values should not be included
        expect(uri.queryParameters.containsKey('zoom'), isFalse);
        expect(uri.queryParameters.containsKey('x'), isFalse);
        expect(uri.queryParameters.containsKey('y'), isFalse);
        expect(uri.queryParameters.containsKey('rotX'), isFalse);
      });
    });

    group('DeepLinkData', () {
      test('toViewState creates correct FractalViewState', () {
        final data = DeepLinkData(
          type: 'mandelbrot',
          zoom: 5.0,
          x: -0.5,
          y: 0.25,
          rotX: 0.1,
          rotY: 0.2,
          rotZ: 0.3,
        );

        final viewState = data.toViewState();

        expect(viewState.zoom, closeTo(5.0, 0.001));
        expect(viewState.pan.x, closeTo(-0.5, 0.001));
        expect(viewState.pan.y, closeTo(0.25, 0.001));
        expect(viewState.rotation.x, closeTo(0.1, 0.001));
        expect(viewState.rotation.y, closeTo(0.2, 0.001));
        expect(viewState.rotation.z, closeTo(0.3, 0.001));
      });

      test('toViewState handles null values with defaults', () {
        final data = DeepLinkData(type: 'mandelbrot');

        final viewState = data.toViewState();

        expect(viewState.zoom, 1.0);
        expect(viewState.pan.x, 0.0);
        expect(viewState.pan.y, 0.0);
        expect(viewState.rotation.x, 0.0);
        expect(viewState.rotation.y, 0.0);
        expect(viewState.rotation.z, 0.0);
      });

      test('toParams extracts fractal parameters', () {
        final data = DeepLinkData(
          type: 'mandelbrot',
          iterations: 200,
          colorScheme: 2,
          bailout: 4.5,
          power: 8.0,
        );

        final params = data.toParams();

        expect(params['iterations'], 200);
        expect(params['colorScheme'], 2);
        expect(params['bailout'], 4.5);
        expect(params['power'], 8.0);
      });

      test('toParams omits null values', () {
        final data = DeepLinkData(
          type: 'mandelbrot',
          iterations: 200,
        );

        final params = data.toParams();

        expect(params.containsKey('iterations'), isTrue);
        expect(params.containsKey('colorScheme'), isFalse);
        expect(params.containsKey('bailout'), isFalse);
      });
    });

    group('buildWebUri', () {
      test('creates https URL with fractalforge.app host', () {
        final uri = DeepLinkService.buildWebUri(
          moduleId: 'mandelbrot',
          params: {'iterations': 100},
          view: FractalViewState.initial(),
        );

        expect(uri.scheme, 'https');
        expect(uri.host, 'fractalforge.app');
        expect(uri.path, '/view');
        expect(uri.queryParameters['type'], 'mandelbrot');
        expect(uri.queryParameters['iterations'], '100');
      });
    });

    group('round-trip', () {
      test('URL can be built and parsed back to same data', () {
        final originalView = FractalViewState(
          pan: Vector2(-0.747, 0.1),
          zoom: 25.0,
          rotation: Vector3.zero(),
        );
        final originalParams = {
          'iterations': 350,
          'colorScheme': 1,
          'bailout': 4.0,
        };

        // Build URL
        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: originalParams,
          view: originalView,
        );

        // Parse it back
        final parsed = DeepLinkService.parseUri(uri);

        expect(parsed, isNotNull);
        expect(parsed!.type, 'mandelbrot');
        expect(parsed.zoom, 25.0);
        expect(parsed.x, closeTo(-0.747, 0.001));
        expect(parsed.y, closeTo(0.1, 0.001));
        expect(parsed.iterations, 350);
        expect(parsed.colorScheme, 1);
      });

      test('deep zoom round-trip preserves significant pan digits', () {
        final originalView = FractalViewState(
          pan: Vector2(-0.743643887037151, 0.13182590420533),
          zoom: 1250000000000.0,
          rotation: Vector3.zero(),
        );

        final uri = DeepLinkService.buildUri(
          moduleId: 'mandelbrot',
          params: const {},
          view: originalView,
        );

        final parsed = DeepLinkService.parseUri(uri);

        expect(parsed, isNotNull);
        expect(parsed!.x, closeTo(originalView.pan.x, 1e-15));
        expect(parsed.y, closeTo(originalView.pan.y, 1e-15));
        expect(parsed.zoom, originalView.zoom);
      });

      test('complete round-trip with all parameters preserves values', () {
        final originalView = FractalViewState(
          pan: Vector2(0.3, -0.15),
          zoom: 42.0,
          rotation: Vector3(0.5, 0.3, 0.1),
        );
        final originalParams = {
          'iterations': 500,
          'colorScheme': 3,
          'bailout': 8.0,
          'power': 8.0,
          'juliaX': -0.7,
          'juliaY': 0.27,
        };

        final uri = DeepLinkService.buildUri(
          moduleId: 'julia',
          params: originalParams,
          view: originalView,
        );

        final parsed = DeepLinkService.parseUri(uri);

        expect(parsed, isNotNull);
        expect(parsed!.type, 'julia');
        expect(parsed.zoom, closeTo(42.0, 0.001));
        expect(parsed.x, closeTo(0.3, 0.001));
        expect(parsed.y, closeTo(-0.15, 0.001));
        expect(parsed.rotX, closeTo(0.5, 0.001));
        expect(parsed.rotY, closeTo(0.3, 0.001));
        expect(parsed.rotZ, closeTo(0.1, 0.001));
        expect(parsed.iterations, 500);
        expect(parsed.colorScheme, 3);
        expect(parsed.bailout, closeTo(8.0, 0.001));
        expect(parsed.power, closeTo(8.0, 0.001));
        expect(parsed.juliaX, closeTo(-0.7, 0.001));
        expect(parsed.juliaY, closeTo(0.27, 0.001));
      });

      test('Julia constant round-trip preserves significant digits', () {
        final originalParams = {
          'juliaX': -0.743643887037151,
          'juliaY': 0.13182590420533,
        };

        final uri = DeepLinkService.buildUri(
          moduleId: 'julia',
          params: originalParams,
          view: FractalViewState.initial(),
        );

        final parsed = DeepLinkService.parseUri(uri);

        expect(parsed, isNotNull);
        expect(parsed!.juliaX, closeTo(originalParams['juliaX']!, 1e-15));
        expect(parsed.juliaY, closeTo(originalParams['juliaY']!, 1e-15));
      });
    });

    group('parameter validation — bounds clamping', () {
      test('valid deep link with all parameters is parsed correctly', () {
        final uri = Uri.parse(
          'fractalforge://view?type=mandelbulb'
          '&zoom=50&x=-1.5&y=2.3'
          '&rotX=0.5&rotY=0.3&rotZ=0.1'
          '&iterations=500&bailout=6.0&colorScheme=3'
          '&power=8&juliaX=-0.7&juliaY=0.27',
        );
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbulb');
        expect(data.zoom, closeTo(50.0, 0.001));
        expect(data.x, closeTo(-1.5, 0.001));
        expect(data.y, closeTo(2.3, 0.001));
        expect(data.rotX, closeTo(0.5, 0.001));
        expect(data.rotY, closeTo(0.3, 0.001));
        expect(data.rotZ, closeTo(0.1, 0.001));
        expect(data.iterations, 500);
        expect(data.bailout, closeTo(6.0, 0.001));
        expect(data.colorScheme, 3);
        expect(data.power, closeTo(8.0, 0.001));
        expect(data.juliaX, closeTo(-0.7, 0.001));
        expect(data.juliaY, closeTo(0.27, 0.001));
      });

      test('missing optional parameters return null (not crash)', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.type, 'mandelbrot');
        expect(data.zoom, isNull);
        expect(data.x, isNull);
        expect(data.y, isNull);
        expect(data.rotX, isNull);
        expect(data.rotY, isNull);
        expect(data.rotZ, isNull);
        expect(data.iterations, isNull);
        expect(data.bailout, isNull);
        expect(data.colorScheme, isNull);
        expect(data.power, isNull);
        expect(data.juliaX, isNull);
        expect(data.juliaY, isNull);
      });

      test('malformed zoom value "abc" returns null for zoom', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot&zoom=abc');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, isNull);
      });

      test('malformed iterations value "xyz" returns null for iterations', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&iterations=xyz');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.iterations, isNull);
      });

      test('malformed bailout value "notanumber" returns null for bailout', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&bailout=notanumber');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.bailout, isNull);
      });

      test('zoom above 1e15 is clamped to 1e15', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbrot&zoom=9999999999999999');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, closeTo(1e15, 1e10));
      });

      test('zoom below 0.001 is clamped to 0.001', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&zoom=0.00000001');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, closeTo(0.001, 1e-6));
      });

      test('iterations above 10000 is clamped to 10000', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&iterations=99999');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.iterations, 10000);
      });

      test('negative iterations is clamped to 1', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&iterations=-50');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.iterations, 1);
      });

      test('bailout below minimum (1.0) is clamped to 1.0', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&bailout=0.001');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.bailout, closeTo(1.0, 1e-6));
      });

      test('bailout above 1e10 is clamped to 1e10', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbrot&bailout=99999999999');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.bailout, closeTo(1e10, 1e6));
      });

      test('pan x beyond 1e10 is clamped to 1e10', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&x=99999999999');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.x, closeTo(1e10, 1e6));
      });

      test('pan x below -1e10 is clamped to -1e10', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&x=-99999999999');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.x, closeTo(-1e10, 1e6));
      });

      test('pan y beyond 1e10 is clamped to 1e10', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&y=50000000000');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.y, closeTo(1e10, 1e6));
      });

      test('pan y below -1e10 is clamped to -1e10', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&y=-50000000000');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.y, closeTo(-1e10, 1e6));
      });

      test('module ID with uppercase letters is rejected', () {
        final uri = Uri.parse('fractalforge://view?type=Mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('module ID with special characters is rejected', () {
        final uri = Uri.parse('fractalforge://view?type=../etc/passwd');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('module ID with spaces is rejected', () {
        final uri = Uri.parse('fractalforge://view?type=mandel+brot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('empty type parameter is rejected', () {
        final uri = Uri.parse('fractalforge://view?type=');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('fractalforge:// URL with empty path returns null', () {
        final uri = Uri.parse('fractalforge://other?type=mandelbrot');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNull);
      });

      test('zoom of exactly 0.001 is accepted (at min boundary)', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot&zoom=0.001');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, closeTo(0.001, 1e-9));
      });

      test('zoom of exactly 1e15 is accepted (at max boundary)', () {
        final uri = Uri.parse(
            'fractalforge://view?type=mandelbrot&zoom=1000000000000000');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, closeTo(1e15, 1e10));
      });

      test('iterations of exactly 1 is accepted (at min boundary)', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&iterations=1');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.iterations, 1);
      });

      test('iterations of exactly 10000 is accepted (at max boundary)', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&iterations=10000');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.iterations, 10000);
      });

      test('NaN string for zoom returns null', () {
        final uri = Uri.parse('fractalforge://view?type=mandelbrot&zoom=NaN');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, isNull);
      });

      test('Infinity string for zoom returns null', () {
        final uri =
            Uri.parse('fractalforge://view?type=mandelbrot&zoom=Infinity');
        final data = DeepLinkService.parseUri(uri);

        expect(data, isNotNull);
        expect(data!.zoom, isNull);
      });
    });
  });
